const STOPWORDS = new Set(['the','a','an','and','or','but','in','on','at','to','for','of','with','by','from','up','about','into','through','is','are','was','were','be','been','being','have','has','had','do','does','did','will','would','could','should','may','might','shall','can','i','you','he','she','it','we','they','me','him','her','us','them','my','your','his','its','our','their','this','that','these','those','what','which','who','how','when','where','not','no','so','if','as','than','then','there','here']);
const tokens = input.toLowerCase().match(/\b[a-z']{2,}\b/g) || [];
const freq = {};
for (const w of tokens) {
  if (!STOPWORDS.has(w)) freq[w] = (freq[w] || 0) + 1;
}
const sorted = Object.entries(freq).sort((a, b) => b[1] - a[1]);
const top = sorted.slice(0, 30);
if (top.length === 0) return { output: 'No meaningful words found.', outputLanguage: 'text' };
const maxCount = top[0][1];
const lines = ['Top words (excluding stopwords):', ''];
for (const [word, count] of top) {
  const bar = '#'.repeat(Math.round(count / maxCount * 20));
  lines.push(String(count).padStart(4) + '  ' + word.padEnd(20) + ' ' + bar);
}
return { output: lines.join('\n'), outputLanguage: 'text' };
